import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';

const Admin = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);
  const [tab, setTab] = useState('products');
  const [form, setForm] = useState({
    name: '', description: '', price: '',
    category: '', image: '', stock: ''
  });
  const [msg, setMsg] = useState('');

  useEffect(() => {
    if (!user?.isAdmin) navigate('/');
    fetchProducts();
    fetchOrders();
  }, []);

  const fetchProducts = () =>
    api.get('/products').then((r) => setProducts(r.data));

  const fetchOrders = () =>
    api.get('/orders').then((r) => setOrders(r.data));

  const handleChange = (e) =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const handleAddProduct = async (e) => {
    e.preventDefault();
    try {
      await api.post('/products', {
        ...form,
        price: Number(form.price),
        stock: Number(form.stock),
      });
      setMsg('✅ Product added!');
      setForm({ name: '', description: '', price: '', category: '', image: '', stock: '' });
      fetchProducts();
    } catch (err) {
      setMsg('❌ ' + (err.response?.data?.message || 'Error'));
    }
  };

  const handleDeleteProduct = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    await api.delete(`/products/${id}`);
    fetchProducts();
  };

  const handleStatusUpdate = async (id, status) => {
    await api.put(`/orders/${id}/status`, { status });
    fetchOrders();
  };

  return (
    <div style={{ padding: '24px' }}>
      <h2>⚙️ Admin Panel</h2>

      <div style={{ display: 'flex', gap: '12px', marginBottom: '24px' }}>
        <button
          onClick={() => setTab('products')}
          style={tab === 'products' ? styles.activeTab : styles.tab}
        >
          Products
        </button>
        <button
          onClick={() => setTab('orders')}
          style={tab === 'orders' ? styles.activeTab : styles.tab}
        >
          Orders
        </button>
        <button
          onClick={() => setTab('add')}
          style={tab === 'add' ? styles.activeTab : styles.tab}
        >
          + Add Product
        </button>
      </div>

      {/* ADD PRODUCT TAB */}
      {tab === 'add' && (
        <form onSubmit={handleAddProduct} style={{ maxWidth: '480px' }}>
          <h3>Add New Product</h3>
          {msg && <p>{msg}</p>}
          {['name', 'description', 'price', 'category', 'image', 'stock'].map((field) => (
            <input
              key={field}
              name={field}
              placeholder={field.charAt(0).toUpperCase() + field.slice(1)}
              value={form[field]}
              onChange={handleChange}
              style={styles.input}
              required
            />
          ))}
          <button type="submit" style={styles.btn}>Add Product</button>
        </form>
      )}

      {/* PRODUCTS TAB */}
      {tab === 'products' && (
        <div>
          <h3>All Products ({products.length})</h3>
          {products.map((p) => (
            <div key={p._id} style={styles.row}>
              <img src={p.image} alt={p.name} style={styles.thumb} />
              <span style={{ flex: 1 }}>{p.name}</span>
              <span>${p.price}</span>
              <span style={{ color: '#888', fontSize: '13px' }}>
                Stock: {p.stock}
              </span>
              <button
                onClick={() => handleDeleteProduct(p._id)}
                style={styles.del}
              >
                Delete
              </button>
            </div>
          ))}
        </div>
      )}

      {/* ORDERS TAB */}
      {tab === 'orders' && (
        <div>
          <h3>All Orders ({orders.length})</h3>
          {orders.map((o) => (
            <div key={o._id} style={styles.row}>
              <span>#{o._id.slice(-8)}</span>
              <span>{o.user?.name || 'User'}</span>
              <span>${o.totalPrice.toFixed(2)}</span>
              <select
                value={o.status}
                onChange={(e) => handleStatusUpdate(o._id, e.target.value)}
                style={styles.select}
              >
                {['pending', 'processing', 'shipped', 'delivered', 'cancelled'].map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const styles = {
  tab: { padding: '8px 20px', background: '#eee', border: 'none', borderRadius: '8px', cursor: 'pointer' },
  activeTab: { padding: '8px 20px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer' },
  input: { display: 'block', width: '100%', padding: '10px 14px', margin: '8px 0', borderRadius: '8px', border: '1px solid #ddd', boxSizing: 'border-box' },
  btn: { padding: '10px 24px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', marginTop: '8px' },
  row: { display: 'flex', alignItems: 'center', gap: '16px', padding: '12px', border: '1px solid #eee', borderRadius: '8px', marginBottom: '10px', background: '#fff' },
  thumb: { width: '50px', height: '50px', objectFit: 'cover', borderRadius: '6px' },
  del: { background: '#ff4444', color: '#fff', border: 'none', padding: '6px 12px', borderRadius: '6px', cursor: 'pointer' },
  select: { padding: '6px 10px', borderRadius: '6px', border: '1px solid #ddd' },
};

export default Admin;
